 305→export async function authWithRetry(
 306→  config: ClientConfig,
 307→  opts?: { maxAttempts?: number; baseDelayMs?: number },
 308→): Promise<AuthResult> {
 309→  const maxAttempts = opts?.maxAttempts ?? 5;
 310→  const baseDelay = opts?.baseDelayMs ?? 5000;
 311→  let lastError: unknown;
 312→  for (let attempt = 0; attempt < maxAttempts; attempt++) {
 313→    try {
 314→      return await authHandshake(config);
 315→    } catch (err) {
 316→      if (!(err instanceof ReconnectRequiredError)) throw err;
 317→      lastError = err;
 318→      if (attempt + 1 < maxAttempts) {
 319→        const delay = Math.min(baseDelay * 2 ** attempt, 60000);
 320→        await Bun.sleep(delay);
 321→      }
 322→    }
 323→  }
 324→  throw lastError;
 325→}
