 327→type AuthContext = {
 328→  buf: AccumulatorBuffer;
 329→  srp: SRP;
 330→  phase: "challenge" | "proof" | "reconnect_proof" | "realms";
 331→  config: ClientConfig;
 332→  srpResult?: SRPResult;
 333→  sessionKey?: Uint8Array;
 334→};
 335→
 336→function advanceAuth(ctx: AuthContext, socket: Socket): AuthResult | undefined {
 337→  const raw = ctx.buf.peek(ctx.buf.length);
 338→  let result: AuthResult | undefined;
 339→
 340→  if (ctx.phase === "challenge") {
 341→    if (raw[0] === AuthOpcode.RECONNECT_CHALLENGE) {
 342→      socket.write(handleReconnectChallenge(raw, ctx.config));
 343→      ctx.sessionKey = ctx.config.cachedSessionKey!;
 344→      ctx.phase = "reconnect_proof";
 345→    } else {
 346→      ctx.srpResult = handleChallenge(raw, ctx.config, ctx.srp);
 347→      ctx.sessionKey = ctx.srpResult.K;
 348→      socket.write(buildLogonProof(ctx.srpResult));
 349→      ctx.phase = "proof";
 350→    }
 351→  } else if (ctx.phase === "proof") {
 352→    handleProof(raw, ctx.srpResult!);
 353→    socket.write(buildRealmListRequest());
 354→    ctx.phase = "realms";
 355→  } else if (ctx.phase === "reconnect_proof") {
 356→    handleReconnectProof(raw);
 357→    socket.write(buildRealmListRequest());
 358→    ctx.phase = "realms";
 359→  } else {
 360→    result = { sessionKey: ctx.sessionKey!, ...handleRealms(raw) };
 361→  }
 362→
 363→  ctx.buf.drain(ctx.buf.length);
 364→  return result;
 365→}
