 367→export function authHandshake(config: ClientConfig): Promise<AuthResult> {
 368→  return new Promise((resolve, reject) => {
 369→    const ctx: AuthContext = {
 370→      buf: new AccumulatorBuffer(),
 371→      srp: new SRP(config.account, config.password),
 372→      phase: "challenge",
 373→      config,
 374→    };
 375→    let done = false;
 376→
 377→    Bun.connect({
 378→      hostname: config.host,
 379→      port: config.port,
 380→      socket: {
 381→        open(socket) {
 382→          socket.write(buildLogonChallenge(config.account));
 383→        },
 384→        data(socket, data) {
 385→          ctx.buf.append(new Uint8Array(data));
 386→          try {
 387→            const result = advanceAuth(ctx, socket);
 388→            if (result) {
 389→              done = true;
 390→              socket.end();
 391→              resolve(result);
 392→            }
 393→          } catch (err) {
 394→            if (err instanceof RangeError) return;
 395→            done = true;
 396→            reject(err);
 397→            socket.end();
 398→          }
 399→        },
 400→        close() {
 401→          if (!done) reject(new Error("Auth connection closed"));
 402→        },
 403→      },
 404→    }).catch(reject);
 405→  });
 406→}
