 462→function resolveAndDeliver(conn: WorldConn, raw: RawChatMessage): void {
 463→  if (raw.senderGuidLow === 0) {
 464→    deliverMessage(conn, raw, "");
 465→    return;
 466→  }
 467→
 468→  const cached = conn.nameCache.get(raw.senderGuidLow);
 469→  if (cached !== undefined) {
 470→    deliverMessage(conn, raw, cached);
 471→    return;
 472→  }
 473→
 474→  const pending = conn.pendingMessages.get(raw.senderGuidLow);
 475→  if (pending) {
 476→    pending.push(raw);
 477→  } else {
 478→    conn.pendingMessages.set(raw.senderGuidLow, [raw]);
 479→    sendPacket(
 480→      conn,
 481→      GameOpcode.CMSG_NAME_QUERY,
 482→      buildNameQuery(raw.senderGuidLow, raw.senderGuidHigh),
 483→    );
 484→  }
 485→}
