 635→function handleUpdateObject(conn: WorldConn, r: PacketReader): void {
 636→  const entries = parseUpdateObject(r);
 637→  for (const entry of entries) {
 638→    switch (entry.type) {
 639→      case "create": {
 640→        const { _changed: _co, ...objFields } = extractObjectFields(
 641→          entry.fields,
 642→        );
 643→        let extraFields: Record<string, unknown> = {};
 644→        if (
 645→          entry.objectType === ObjectType.UNIT ||
 646→          entry.objectType === ObjectType.PLAYER
 647→        ) {
 648→          const { _changed: _cu, ...rest } = extractUnitFields(entry.fields);
 649→          extraFields = rest;
 650→        } else if (entry.objectType === ObjectType.GAMEOBJECT) {
 651→          const { _changed: _cg, ...rest } = extractGameObjectFields(
 652→            entry.fields,
 653→          );
 654→          extraFields = rest;
 655→        }
 656→        const cachedName = lookupCachedName(
 657→          conn,
 658→          entry.guid,
 659→          entry.objectType,
 660→          objFields.entry,
 661→        );
 662→        conn.entityStore.create(entry.guid, entry.objectType, {
 663→          ...objFields,
 664→          ...extraFields,
 665→          ...(cachedName ? { name: cachedName } : {}),
 666→          ...(entry.position ? { position: entry.position } : {}),
 667→          rawFields: new Map(entry.fields),
 668→        } as any);
 669→        if (!cachedName) {
 670→          queryEntityName(conn, entry.guid, entry.objectType, objFields.entry);
 671→        }
 672→        break;
 673→      }
 674→      case "values": {
 675→        const entity = conn.entityStore.get(entry.guid);
 676→        if (!entity) break;
 677→        const objFields = extractObjectFields(entry.fields, entity.rawFields);
 678→        let extraFields: Record<string, unknown> = {};
 679→        if (
 680→          entity.objectType === ObjectType.UNIT ||
 681→          entity.objectType === ObjectType.PLAYER
 682→        ) {
 683→          extraFields = extractUnitFields(entry.fields, entity.rawFields);
 684→        } else if (entity.objectType === ObjectType.GAMEOBJECT) {
 685→          extraFields = extractGameObjectFields(entry.fields);
 686→        }
 687→        const allChanged = [
 688→          ...(objFields._changed || []),
 689→          ...((extraFields as any)._changed || []),
 690→        ];
 691→        const merged: Record<string, unknown> = {};
 692→        for (const key of allChanged) {
 693→          if (key in extraFields) merged[key] = (extraFields as any)[key];
 694→          else if (key in objFields) merged[key] = (objFields as any)[key];
 695→        }
 696→        conn.entityStore.update(entry.guid, merged);
 697→        for (const [k, v] of entry.fields) {
 698→          const existing = conn.entityStore.get(entry.guid);
 699→          if (existing) existing.rawFields.set(k, v);
 700→        }
 701→        break;
 702→      }
 703→      case "movement": {
 704→        conn.entityStore.setPosition(entry.guid, entry.position);
 705→        break;
 706→      }
 707→      case "outOfRange": {
 708→        for (const guid of entry.guids) conn.entityStore.destroy(guid);
 709→        break;
 710→      }
 711→      case "nearObjects": {
 712→        break;
 713→      }
 714→    }
 715→  }
 716→}
