 718→function handleCompressedUpdateObject(conn: WorldConn, r: PacketReader): void {
 719→  const uncompressedSize = r.uint32LE();
 720→  const compressed = r.bytes(r.remaining);
 721→  const decompressed = inflateSync(compressed);
 722→  if (decompressed.length !== uncompressedSize) {
 723→    throw new Error(
 724→      `Compressed update size mismatch: expected ${uncompressedSize}, got ${decompressed.length}`,
 725→    );
 726→  }
 727→  handleUpdateObject(conn, new PacketReader(new Uint8Array(decompressed)));
 728→}
