 736→function lookupCachedName(
 737→  conn: WorldConn,
 738→  guid: bigint,
 739→  objectType: number,
 740→  entry: number | undefined,
 741→): string | undefined {
 742→  if (objectType === ObjectType.PLAYER) {
 743→    const guidLow = Number(guid & 0xffffffffn);
 744→    return conn.nameCache.get(guidLow);
 745→  }
 746→  if (entry === undefined) return undefined;
 747→  if (objectType === ObjectType.UNIT) return conn.creatureNameCache.get(entry);
 748→  if (objectType === ObjectType.GAMEOBJECT)
 749→    return conn.gameObjectNameCache.get(entry);
 750→  return undefined;
 751→}
