 753→function queryEntityName(
 754→  conn: WorldConn,
 755→  guid: bigint,
 756→  objectType: number,
 757→  entry: number | undefined,
 758→): void {
 759→  if (objectType === ObjectType.PLAYER) {
 760→    const guidLow = Number(guid & 0xffffffffn);
 761→    const key = `player:${guidLow}`;
 762→    if (conn.pendingNameQueries.has(key)) return;
 763→    conn.pendingNameQueries.add(key);
 764→    const w = new PacketWriter();
 765→    w.uint64LE(guid);
 766→    sendPacket(conn, GameOpcode.CMSG_NAME_QUERY, w.finish());
 767→    return;
 768→  }
 769→  if (entry === undefined) return;
 770→  const key = `${objectType}:${entry}`;
 771→  if (conn.pendingNameQueries.has(key)) return;
 772→  conn.pendingNameQueries.add(key);
 773→  if (objectType === ObjectType.UNIT) {
 774→    sendPacket(
 775→      conn,
 776→      GameOpcode.CMSG_CREATURE_QUERY,
 777→      buildCreatureQuery(entry, guid),
 778→    );
 779→    return;
 780→  }
 781→  if (objectType === ObjectType.GAMEOBJECT) {
 782→    sendPacket(
 783→      conn,
 784→      GameOpcode.CMSG_GAMEOBJECT_QUERY,
 785→      buildGameObjectQuery(entry, guid),
 786→    );
 787→    return;
 788→  }
 789→}
