 836→function handleContactList(conn: WorldConn, r: PacketReader): void {
 837→  const list = parseContactList(r);
 838→  const friends: FriendEntry[] = [];
 839→  for (const contact of list.contacts) {
 840→    if (!(contact.flags & SocialFlag.FRIEND)) continue;
 841→    const guidLow = Number(contact.guid & 0xffffffffn);
 842→    const name = conn.nameCache.get(guidLow) ?? "";
 843→    friends.push({
 844→      guid: contact.guid,
 845→      name,
 846→      note: contact.note,
 847→      status: contact.status ?? 0,
 848→      area: contact.area ?? 0,
 849→      level: contact.level ?? 0,
 850→      playerClass: contact.playerClass ?? 0,
 851→    });
 852→    if (!name && !conn.pendingNameQueries.has(`player:${guidLow}`)) {
 853→      conn.pendingNameQueries.add(`player:${guidLow}`);
 854→      sendPacket(
 855→        conn,
 856→        GameOpcode.CMSG_NAME_QUERY,
 857→        buildNameQuery(guidLow, Number((contact.guid >> 32n) & 0xffffffffn)),
 858→      );
 859→    }
 860→  }
 861→  conn.friendStore.set(friends);
 862→}
