 948→async function selectCharacter(
 949→  conn: WorldConn,
 950→  config: ClientConfig,
 951→): Promise<void> {
 952→  sendPacket(conn, GameOpcode.CMSG_CHAR_ENUM);
 953→
 954→  const enumReader = await conn.dispatch.expect(GameOpcode.SMSG_CHAR_ENUM);
 955→  const chars = parseCharacterList(enumReader);
 956→  const char = chars.find(
 957→    (c) => c.name.toLowerCase() === config.character.toLowerCase(),
 958→  );
 959→  if (!char) {
 960→    throw new Error(
 961→      `Character "${config.character}" not found. Available: ${chars.map((c) => c.name).join(", ")}`,
 962→    );
 963→  }
 964→
 965→  conn.selfName = char.name;
 966→  conn.selfGuidLow = char.guidLow;
 967→  conn.selfGuidHigh = char.guidHigh;
 968→
 969→  const w = new PacketWriter();
 970→  w.uint32LE(char.guidLow);
 971→  w.uint32LE(char.guidHigh);
 972→  sendPacket(conn, GameOpcode.CMSG_PLAYER_LOGIN, w.finish());
 973→
 974→  await conn.dispatch.expect(GameOpcode.SMSG_LOGIN_VERIFY_WORLD);
 975→}
