 37→  | { type: "quit" }
 38→  | { type: "tuicraft"; subcommand: string; value: string }
 39→  | { type: "friends" }
 40→  | { type: "add-friend"; target: string }
 41→  | { type: "remove-friend"; target: string }
 42→  | { type: "roll"; min: number; max: number }
 43→  | { type: "unimplemented"; feature: string };
 44→
 45→export function parseCommand(input: string): Command {
 46→  if (!input.startsWith("/")) return { type: "chat", message: input };
 47→
 48→  const spaceIdx = input.indexOf(" ");
 49→  const cmd = spaceIdx === -1 ? input : input.slice(0, spaceIdx);
 50→  const rest = spaceIdx === -1 ? "" : input.slice(spaceIdx + 1);
 51→
 52→  switch (cmd) {
 53→    case "/s":
 54→    case "/say":
 55→      return { type: "say", message: rest };
 56→    case "/y":
 57→    case "/yell":
 58→      return { type: "yell", message: rest };
 59→    case "/g":
 60→    case "/guild":
 61→      return { type: "guild", message: rest };
 62→    case "/p":
 63→    case "/party":
 64→      return { type: "party", message: rest };
 65→    case "/raid":
 66→      return { type: "raid", message: rest };
 67→    case "/w":
 68→    case "/whisper": {
 69→      const targetEnd = rest.indexOf(" ");
 70→      if (targetEnd === -1)
 71→        return { type: "whisper", target: rest, message: "" };
 72→      return {
 73→        type: "whisper",
 74→        target: rest.slice(0, targetEnd),
 75→        message: rest.slice(targetEnd + 1),
 76→      };
 77→    }
 78→    case "/r":
 79→      return { type: "reply", message: rest };
 80→    case "/who":
 81→      return rest ? { type: "who", target: rest } : { type: "who" };
 82→    case "/invite":
 83→      return rest
 84→        ? { type: "invite", target: rest }
 85→        : { type: "say", message: input };
 86→    case "/kick":
 87→      return rest
 88→        ? { type: "kick", target: rest }
 89→        : { type: "say", message: input };
 90→    case "/leave":
 91→      return { type: "leave" };
 92→    case "/leader":
 93→      return rest
 94→        ? { type: "leader", target: rest }
 95→        : { type: "say", message: input };
 96→    case "/accept":
 97→      return { type: "accept" };
 98→    case "/decline":
 99→      return { type: "decline" };
100→    case "/quit":
101→      return { type: "quit" };
102→    case "/tuicraft": {
103→      const parts = rest.split(" ");
104→      return {
105→        type: "tuicraft",
106→        subcommand: parts[0] ?? "",
107→        value: parts[1] ?? "",
108→      };
109→    }
110→    case "/friends":
111→      return { type: "friends" };
112→    case "/f":
113→      return { type: "friends" };
114→    case "/friend": {
115→      const parts = rest.split(" ");
116→      const sub = parts[0] ?? "";
117→      const target = parts.slice(1).join(" ");
118→      if (sub === "add" && target) return { type: "add-friend", target };
119→      if (sub === "remove" && target) return { type: "remove-friend", target };
120→      return { type: "friends" };
121→    }
122→    case "/ignore":
123→      return { type: "unimplemented", feature: "Ignore list" };
124→    case "/join":
125→      return { type: "unimplemented", feature: "Channel join/leave" };
126→    case "/ginvite":
127→    case "/gkick":
128→    case "/gleave":
129→    case "/gpromote":
130→      return { type: "unimplemented", feature: "Guild management" };
131→    case "/mail":
132→      return { type: "unimplemented", feature: "Mail" };
133→    case "/roll": {
134→      const parts = rest.split(" ").filter(Boolean);
135→      if (parts.length >= 2)
136→        return {
137→          type: "roll",
138→          min: parseInt(parts[0]!, 10),
139→          max: parseInt(parts[1]!, 10),
140→        };
141→      if (parts.length === 1)
142→        return { type: "roll", min: 1, max: parseInt(parts[0]!, 10) };
143→      return { type: "roll", min: 1, max: 100 };
144→    }
145→    case "/dnd":
146→      return { type: "dnd", message: rest };
147→    case "/afk":
148→      return { type: "afk", message: rest };
149→    case "/e":
150→    case "/emote":
151→      return { type: "emote", message: rest };
152→    default: {
153→      const channelMatch = cmd.match(/^\/(\d+)$/);
154→      if (channelMatch) {
155→        return { type: "channel", target: channelMatch[1]!, message: rest };
156→      }
157→      return { type: "say", message: input };
158→    }
159→  }
160→}
