180→export function formatMessage(msg: ChatMessage): string {
181→  const message = stripColorCodes(msg.message);
182→  const label = CHAT_TYPE_LABELS[msg.type] ?? `type ${msg.type}`;
183→
184→  if (msg.type === ChatType.WHISPER) {
185→    return `[whisper from ${msg.sender}] ${message}`;
186→  }
187→  if (msg.type === ChatType.WHISPER_INFORM) {
188→    return `[whisper to ${msg.sender}] ${message}`;
189→  }
190→  if (msg.type === ChatType.SYSTEM) {
191→    return `[system] ${message}`;
192→  }
193→  if (msg.type === ChatType.ROLL) {
194→    return `[roll] ${msg.sender} ${message}`;
195→  }
196→  if (msg.type === ChatType.CHANNEL && msg.channel) {
197→    return `[${msg.channel}] ${msg.sender}: ${message}`;
198→  }
199→  return `[${label}] ${msg.sender}: ${message}`;
200→}
