326→export function formatEntityEvent(event: EntityEvent): string | undefined {
327→  switch (event.type) {
328→    case "appear": {
329→      const e = event.entity;
330→      if (!e.name) return undefined;
331→      if (
332→        e.objectType === ObjectType.UNIT ||
333→        e.objectType === ObjectType.PLAYER
334→      ) {
335→        const unit = e as UnitEntity;
336→        const kind = e.objectType === ObjectType.PLAYER ? "Player" : "NPC";
337→        const levelStr = unit.level > 0 ? `, level ${unit.level}` : "";
338→        return `[world] ${e.name} appeared (${kind}${levelStr})`;
339→      }
340→      if (e.objectType === ObjectType.GAMEOBJECT) {
341→        return `[world] ${e.name} appeared (GameObject)`;
342→      }
343→      return undefined;
344→    }
345→    case "disappear": {
346→      const name = event.name ?? "Unknown entity";
347→      return `[world] ${name} left range`;
348→    }
349→    case "update": {
350→      if (!event.changed.includes("name") || !event.entity.name)
351→        return undefined;
352→      return formatEntityEvent({ type: "appear", entity: event.entity });
353→    }
354→  }
355→}
