416→export function formatFriendList(friends: FriendEntry[]): string {
417→  if (friends.length === 0) return "[friends] No friends on your list";
418→  const lines = friends.map((f) => {
419→    const name = f.name || `guid:${Number(f.guid & 0xffffffffn)}`;
420→    if (f.status === FriendStatus.OFFLINE) return `  ${name} — Offline`;
421→    const cls = CLASS_NAMES[f.playerClass] ?? `class ${f.playerClass}`;
422→    const statusLabel = friendStatusLabel(f.status);
423→    return `  ${name} — ${statusLabel}, Level ${f.level} ${cls}`;
424→  });
425→  const online = friends.filter(
426→    (f) => f.status !== FriendStatus.OFFLINE,
427→  ).length;
428→  return `[friends] ${online}/${friends.length} online\n${lines.join("\n")}`;
429→}
