 95→function onSocketData(ctx: ServerCtx, socket: IpcSocket, data: Buffer): void {
 96→  const state = getSocketState(socket);
 97→  state.buffer += Buffer.from(data).toString();
 98→  const breakIdx = state.buffer.indexOf("\n");
 99→  if (breakIdx === -1) return;
100→  const line = state.buffer.slice(0, breakIdx).trim();
101→  state.buffer = state.buffer.slice(breakIdx + 1);
102→  processLine(ctx, socket, line);
